import sqlite3
from contextlib import contextmanager

# Database schema
class User:
    def __init__(self, id, access_level):
        self.id = id
        self.access_level = access_level

class File:
    def __init__(self, id, user_id, contents):
        self.id = id
        self.user_id = user_id
        self.contents = contents

# Database connection and cursor
conn = sqlite3.connect('document_management.db')
cursor = conn.cursor()

# Create tables if they don't exist
cursor.execute('''
    CREATE TABLE IF NOT EXISTS users (
        id INTEGER PRIMARY KEY,
        access_level TEXT
    )
''')

cursor.execute('''
    CREATE TABLE IF NOT EXISTS files (
        id INTEGER PRIMARY KEY,
        user_id INTEGER,
        contents TEXT,
        FOREIGN KEY (user_id) REFERENCES users(id)
    )
''')

# Context manager for database transactions
@contextmanager
def transaction():
    try:
        yield
        conn.commit()
    except Exception as e:
        conn.rollback()
        raise e

# Function to check user's access level
def get_user_access_level(user_id):
    cursor.execute('SELECT access_level FROM users WHERE id = ?', (user_id,))
    return cursor.fetchone()[0]

# Function to open and read file contents
def open_file(file_id, user_id):
    with transaction():
        # Check if user has permission to read the file
        access_level = get_user_access_level(user_id)
        cursor.execute('SELECT * FROM files WHERE id = ? AND user_id = ?', (file_id, user_id))
        file_data = cursor.fetchone()
        
        if file_data and access_level == 'admin':
            return file_data[2]
        else:
            raise PermissionError('User does not have permission to read the file')

# Example usage
user1 = User(1, 'admin')
file1 = File(1, 1, 'Hello World!')

with transaction():
    cursor.execute('INSERT INTO users VALUES (?, ?)', (user1.id, user1.access_level))
    cursor.execute('INSERT INTO files VALUES (?, ?, ?)', (file1.id, file1.user_id, file1.contents))

print(open_file(file1.id, user1.id))  # Should print 'Hello World!'